import { CRM_DEFAULTS } from '../constants'
import type { CRMLead } from '../types'

const LEAD_PREFIX = CRM_DEFAULTS.LEAD_CODE_PREFIX || 'LEAD'

const getSequenceKeys = (companyId: string, year: number) => ({
  storageKey: `crm_lead_seq_${companyId}_${year}`,
  initKey: `crm_lead_seq_init_${companyId}_${year}`
})

const formatLeadCode = (year: number, sequence: number) =>
  `${LEAD_PREFIX}-${year}-${sequence.toString().padStart(3, '0')}`

const parseLeadCode = (code: string): { year: number; sequence: number } | null => {
  const match = new RegExp(`^${LEAD_PREFIX}-(\\d{4})-(\\d+)$`).exec(code)
  if (!match) return null
  const year = Number(match[1])
  const sequence = Number(match[2])
  if (Number.isNaN(year) || Number.isNaN(sequence)) return null
  return { year, sequence }
}

const getMaxSequenceFromLeads = (leads: CRMLead[], year: number): number => {
  let max = 0
  leads.forEach((lead) => {
    const parsed = lead.leadCode ? parseLeadCode(lead.leadCode) : null
    if (!parsed || parsed.year !== year) return
    if (parsed.sequence > max) max = parsed.sequence
  })
  return max
}

const getStoredSequence = (storageKey: string): number => {
  const stored = localStorage.getItem(storageKey)
  if (!stored) return 0
  const parsed = parseInt(stored, 10)
  return Number.isNaN(parsed) ? 0 : parsed
}

export const previewLeadCode = async (
  companyId: string | null,
  loadExistingLeads?: () => Promise<CRMLead[]>
): Promise<string> => {
  const year = new Date().getFullYear()
  const scopeId = companyId || 'anonymous'
  const { storageKey, initKey } = getSequenceKeys(scopeId, year)
  const isInitialized = localStorage.getItem(initKey) === 'true'

  let current = getStoredSequence(storageKey)

  if (!isInitialized) {
    let maxSequence = 0
    if (loadExistingLeads) {
      try {
        const leads = await loadExistingLeads()
        maxSequence = getMaxSequenceFromLeads(leads, year)
      } catch (error) {
        console.warn('Failed to load existing leads for sequence seed:', error)
      }
    }
    current = Math.max(current, maxSequence)
  }

  return formatLeadCode(year, current + 1)
}

export const commitLeadCode = async (
  companyId: string | null,
  leadCode: string,
  loadExistingLeads?: () => Promise<CRMLead[]>
): Promise<void> => {
  const parsed = parseLeadCode(leadCode)
  if (!parsed) return

  const scopeId = companyId || 'anonymous'
  const { storageKey, initKey } = getSequenceKeys(scopeId, parsed.year)
  const isInitialized = localStorage.getItem(initKey) === 'true'

  let current = getStoredSequence(storageKey)

  if (!isInitialized) {
    let maxSequence = 0
    if (loadExistingLeads) {
      try {
        const leads = await loadExistingLeads()
        maxSequence = getMaxSequenceFromLeads(leads, parsed.year)
      } catch (error) {
        console.warn('Failed to load existing leads for sequence seed:', error)
      }
    }
    current = Math.max(current, maxSequence)
    localStorage.setItem(initKey, 'true')
  }

  const committed = Math.max(current, parsed.sequence)
  localStorage.setItem(storageKey, committed.toString())
}
