// Pipeline Stages Service
// Manages custom pipeline stages that can be added/edited by admin

import { CRM_STAGES } from '../constants';

export interface CustomPipelineStage {
  id: string;
  key: string;
  label: string;
  color: string;
  order: number;
  isCustom: boolean;
  isLocked?: boolean; // First stage "Lead" is locked
  category: 'prospect' | 'active' | 'closed';
}

const STORAGE_KEY = 'crm_custom_pipeline_stages';

// Default stage colors for new custom stages
const STAGE_COLORS = [
  'bg-blue-100 text-blue-800',
  'bg-green-100 text-green-800',
  'bg-yellow-100 text-yellow-800',
  'bg-purple-100 text-purple-800',
  'bg-indigo-100 text-indigo-800',
  'bg-orange-100 text-orange-800',
  'bg-pink-100 text-pink-800',
  'bg-teal-100 text-teal-800',
  'bg-cyan-100 text-cyan-800',
  'bg-lime-100 text-lime-800',
];

/**
 * Get default stages from CRM_STAGES constant
 */
export function getDefaultStages(): CustomPipelineStage[] {
  return Object.entries(CRM_STAGES).map(([key, stage], index) => ({
    id: key,
    key: key,
    label: stage.label,
    color: stage.color,
    order: stage.order,
    isCustom: false,
    isLocked: key === 'lead_created', // First stage is locked
    category: stage.category
  }));
}

/**
 * Get custom stages from localStorage
 */
export function getCustomStages(): CustomPipelineStage[] {
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored) {
      return JSON.parse(stored);
    }
  } catch (error) {
    console.error('Error loading custom pipeline stages:', error);
  }
  return [];
}

/**
 * Save custom stages to localStorage
 */
export function saveCustomStages(stages: CustomPipelineStage[]): boolean {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(stages));
    return true;
  } catch (error) {
    console.error('Error saving custom pipeline stages:', error);
    return false;
  }
}

/**
 * Get all pipeline stages (custom settings merged with defaults)
 * Returns stages sorted by order
 */
export function getPipelineStages(): CustomPipelineStage[] {
  const customStages = getCustomStages();

  // If custom stages exist, use them
  if (customStages.length > 0) {
    return customStages.sort((a, b) => a.order - b.order);
  }

  // Otherwise return defaults
  return getDefaultStages().sort((a, b) => a.order - b.order);
}

/**
 * Get active (non-closed) pipeline stages for progress display
 */
export function getActivePipelineStages(): CustomPipelineStage[] {
  return getPipelineStages().filter(s => s.category !== 'closed');
}

/**
 * Add a new custom stage
 */
export function addCustomStage(label: string, insertAfterOrder?: number): CustomPipelineStage {
  const stages = getPipelineStages();
  const maxOrder = Math.max(...stages.map(s => s.order));

  // Generate unique key
  const key = `custom_${Date.now()}`;

  // Get a color (cycle through available colors)
  const colorIndex = stages.filter(s => s.isCustom).length % STAGE_COLORS.length;

  const newOrder = insertAfterOrder !== undefined
    ? insertAfterOrder + 0.5
    : maxOrder + 1;

  const newStage: CustomPipelineStage = {
    id: key,
    key: key,
    label: label,
    color: STAGE_COLORS[colorIndex],
    order: newOrder,
    isCustom: true,
    isLocked: false,
    category: 'active'
  };

  // Add new stage and reorder
  const updatedStages = [...stages, newStage];

  // Normalize orders
  const sortedStages = updatedStages.sort((a, b) => a.order - b.order);
  sortedStages.forEach((s, i) => s.order = i + 1);

  saveCustomStages(sortedStages);

  return newStage;
}

/**
 * Update a stage label
 */
export function updateStageLabel(stageKey: string, newLabel: string): boolean {
  const stages = getPipelineStages();
  const stageIndex = stages.findIndex(s => s.key === stageKey);

  if (stageIndex === -1) return false;

  stages[stageIndex].label = newLabel;
  return saveCustomStages(stages);
}

/**
 * Update stage color
 */
export function updateStageColor(stageKey: string, newColor: string): boolean {
  const stages = getPipelineStages();
  const stageIndex = stages.findIndex(s => s.key === stageKey);

  if (stageIndex === -1) return false;

  stages[stageIndex].color = newColor;
  return saveCustomStages(stages);
}

/**
 * Delete a stage (cannot delete locked stages like "Lead Created")
 */
export function deleteStage(stageKey: string): boolean {
  const stages = getPipelineStages();
  const stage = stages.find(s => s.key === stageKey);

  // Cannot delete locked stages (first stage "Lead Created" is locked)
  if (!stage || stage.isLocked) {
    return false;
  }

  const updatedStages = stages.filter(s => s.key !== stageKey);

  // Normalize orders
  updatedStages.sort((a, b) => a.order - b.order);
  updatedStages.forEach((s, i) => s.order = i + 1);

  return saveCustomStages(updatedStages);
}

/**
 * Reorder stages (move a stage to a new position)
 */
export function reorderStages(stageKey: string, newOrder: number): boolean {
  const stages = getPipelineStages();
  const stageIndex = stages.findIndex(s => s.key === stageKey);

  if (stageIndex === -1) return false;

  const stage = stages[stageIndex];

  // Cannot move locked stage (Lead Created must be first)
  if (stage.isLocked) return false;

  // Cannot move to position 1 (reserved for Lead Created)
  if (newOrder <= 1) return false;

  // Update order
  stage.order = newOrder - 0.5; // Use fractional order to insert

  // Normalize orders
  const sortedStages = stages.sort((a, b) => a.order - b.order);
  sortedStages.forEach((s, i) => s.order = i + 1);

  return saveCustomStages(sortedStages);
}

/**
 * Move stage up in order
 */
export function moveStageUp(stageKey: string): boolean {
  const stages = getPipelineStages();
  const stageIndex = stages.findIndex(s => s.key === stageKey);

  if (stageIndex <= 1) return false; // Can't move first stage or if already second

  const stage = stages[stageIndex];
  if (stage.isLocked) return false;

  // Swap with previous stage
  const prevStage = stages[stageIndex - 1];
  if (prevStage.isLocked) return false; // Can't swap with locked stage

  const tempOrder = stage.order;
  stage.order = prevStage.order;
  prevStage.order = tempOrder;

  return saveCustomStages(stages.sort((a, b) => a.order - b.order));
}

/**
 * Move stage down in order
 */
export function moveStageDown(stageKey: string): boolean {
  const stages = getPipelineStages();
  const stageIndex = stages.findIndex(s => s.key === stageKey);

  if (stageIndex === -1 || stageIndex >= stages.length - 1) return false;

  const stage = stages[stageIndex];
  if (stage.isLocked) return false;

  // Swap with next stage
  const nextStage = stages[stageIndex + 1];

  const tempOrder = stage.order;
  stage.order = nextStage.order;
  nextStage.order = tempOrder;

  return saveCustomStages(stages.sort((a, b) => a.order - b.order));
}

/**
 * Reset to default stages
 */
export function resetToDefaultStages(): boolean {
  try {
    localStorage.removeItem(STORAGE_KEY);
    return true;
  } catch (error) {
    console.error('Error resetting pipeline stages:', error);
    return false;
  }
}

/**
 * Get stage by key
 */
export function getStageByKey(stageKey: string): CustomPipelineStage | undefined {
  return getPipelineStages().find(s => s.key === stageKey);
}

/**
 * Check if a stage key is valid (exists in pipeline)
 */
export function isValidStage(stageKey: string): boolean {
  return getPipelineStages().some(s => s.key === stageKey);
}

/**
 * Get stage info (label and color) by key
 * Falls back to CRM_STAGES if not found in custom stages
 */
export function getStageInfo(stageKey: string): { label: string; color: string } {
  const customStage = getStageByKey(stageKey);
  if (customStage) {
    return { label: customStage.label, color: customStage.color };
  }

  // Fallback to built-in stages
  const builtInStage = CRM_STAGES[stageKey as keyof typeof CRM_STAGES];
  if (builtInStage) {
    return { label: builtInStage.label, color: builtInStage.color };
  }

  return { label: stageKey, color: 'bg-gray-100 text-gray-800' };
}
